var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 10월 28일. 평행 세계 런던, <color=#ffd34c>황금 새벽회</color> 지하 사원\\n<color=#ffd34c>심야</color>","JPN":"1888年10月28日。パラレルワールドのロンドン、<color=#ffd34c>黄金の暁団</color>地下寺院\\n<color=#ffd34c>深夜</color>","ENG":"October 28, 1888, Parallel World London, <color=#ffd34c>Golden Dawn</color> Underground Temple\\n<color=#ffd34c>Midnight</color>","TWN":"1888年10月28日。平行世界倫敦，<color=#ffd34c>黃金黎明會</color>地下寺廟\\n<color=#ffd34c>深夜</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"모든 이야기를 처음으로 되돌린다고?","JPN":"全ての物語を振り出しに戻すって？","ENG":"Revert all the stories to their beginning?","TWN":"要把所有故事都回到起點嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 정말로 멸망해 버린 세계를 되돌리는 게 가능하단 말이야……?","JPN":"じゃあ、本当に滅亡した世界を元に戻すことが可能なの……？","ENG":"You mean it's actually possible to bring back a world that was completely destroyed...?","TWN":"真的有可能讓已經毀滅的世界恢復原狀嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그건 무모한 이야기야, 아이린!","JPN":"それは無謀な話だ、アイリーン！","ENG":"That's madness, Irene!","TWN":"那是個魯莽的事，愛琳！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마가 저질렀던 천사 강림 의식은 그저 엉터리 의식에 불과해!","JPN":"深夜の殺人鬼が行った天使降臨の儀式は、ただのデタラメに過ぎない！","ENG":"The angel summoning ritual committed by the Midnight Killer was just a farce!","TWN":"午夜殺人魔所進行的天使降臨儀式不過是個荒唐的儀式而已！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하물며 천사라는 것이 존재한다고 해도, 정말 자네가 원하는 것을 이루어 줄 수 있을까?","JPN":"仮に天使というものが存在したとして、それが本当に君の望みを叶えられるのかね？","ENG":"Even if angels were real, would they really give you what you want?","TWN":"即便天使真的存在，真的能實現你的願望嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다시 한번 생각해 보게……!","JPN":"もう一度考えてみたまえ……！","ENG":"Please reconsider...!","TWN":"再好好考慮一下吧！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 세피라라는 힘이 정확히 어떤 식으로 현실에 작용하는지는 모르겠지만…….","JPN":"そのセフィラという力が、具体的にどういう風に現実に作用するのかは知らないが……","ENG":"I don't know exactly how the power of Sephira affects reality...","TWN":"雖然不知道那叫做生命樹的力量究竟是如何作於于現實的……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 자네의 기억을 재구성하는 우회적인 방법으로 세계를 되돌려 놓을 수 있었어.","JPN":"君は、君の記憶を再構成するという遠回りなやり方で世界を元に戻すことに成功した。","ENG":"But you've used it to reconstruct your memories and rewind the world indirectly.","TWN":"你通過重構自己的記憶，以一種迂回的方式將世界恢復了原狀。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아마도 그건 망각의 여신으로부터 미움받는 자네이기에 떠올릴 수 있는 발상이었겠지.","JPN":"おそらくそれは、忘却の女神に愛されなかった君だからこそできた発想だったのだろう。","ENG":"Maybe that's something only you, hated by the goddess of oblivion, could've come up with.","TWN":"也許那是因為你是被遺忘女神所詛咒的人，才能想到這樣的主意吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그렇다고 해도 기억의 당사자인 자네 자신은 과거로 돌아갈 수 없었어.","JPN":"しかし、記憶の当事者である君自身が過去に戻れたわけではなかった。","ENG":"But even so, you yourself couldn't return to the past.","TWN":"但即便如此，作為記憶的主人的你自己也沒能回到過去。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 증거로 이 세계에는 자네가 두 사람 존재하게 되지 않았나?","JPN":"その証拠として、この世界には君が2人存在しているだろう？","ENG":"If you could, why are there two of you in this world?","TWN":"這個世界上還有兩個你存在，這就是證據不是嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니…….","JPN":"言われてみれば……","ENG":"Now that you mention it...","TWN":"這麼說來……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인…….","JPN":"アバーライン……","ENG":"Abberline...","TWN":"艾伯林……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 재밌군요.","JPN":"ふふ、面白いですね。","ENG":"Haha, how amusing.","TWN":"呵呵，真有趣啊。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 그게 뭐 어쨌다는 거죠?","JPN":"それで？　それがどうしたと言うのですか？","ENG":"And what of it?","TWN":"所以那又怎麼樣呢？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"기억을 초월하여, 모든 이야기를 처음으로 되돌리겠다고?","JPN":"記憶を超越して、全ての物語を振り出しに戻すと言ったね？","ENG":"You want to transcend memory and revert all the stories to their beginning?","TWN":"你想超越記憶，要將整個故事回到起點嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"세계를 되돌리더라도, 자네가 지금껏 저질러 왔던 죄는 사라지지 않아.","JPN":"世界を元に戻したところで、君が今まで犯してきた罪が消えるわけではない。","ENG":"Even if you rewind the world, the sins you've committed won't just vanish.","TWN":"即使世界恢復正常，你至今所犯下的罪行也不會消失。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하물며 성공한다고 하더라도, 자네는 지금처럼 어떤 세계에도 속하지 못하게 되겠지.","JPN":"それに成功したとしても、君は今のようにどの世界にも属せなくなるだろう。","ENG":"Even if you succeed, you'll no longer belong to any world.","TWN":"即便成功了，你也將像現在一樣，不屬於任何一個世界。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"결국, 자네는 자네가 만들어낸 세계에서도 외톨이로 남게 될 거야.","JPN":"結局、君は君自身が作り出した世界でも一人ぼっちになるんだ。","ENG":"In the end, even in the world you create, you'll be all alone.","TWN":"最終，你在自己創造的世界中也會成為孤獨者。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"누구에게도 이해받지 못한 채, 누구와도 인연을 맺지 못한 채, 미지의 존재로 남을 거라고!","JPN":"誰からも理解されず、誰かと縁を結ぶこともできず、未知の存在としてただ残されるだけだ！","ENG":"No one will understand you. No one will be connected to you. You'll remain as an unknown to everyone!","TWN":"沒有人理解你，也沒有人與你結緣，你將永遠是個未知的存在！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아이린, 자네가 바라는 세계가 진정 그런 세계인가……?","JPN":"アイリーン、君が望む世界とは、真にそのような世界なのかね……？","ENG":"Is that truly the kind of world you want, Irene...?","TWN":"愛琳，你所期望的世界真的是那樣的世界嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"정녕, 영원히 고독한 존재로 남길 바라는 건가……!","JPN":"本当に、永遠の時を孤独な存在として残ってもいいと言うのか……！","ENG":"Do you really want to remain a lonely existence forever...?!","TWN":"真的希望永遠成為孤獨的存在嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후…….","JPN":"ふふ……","ENG":"Haha...","TWN":"呵呵……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"겉모습은 그럴싸하게 만들어 졌지만, 결국에는 내 기억 속 미련일 뿐인가…….","JPN":"見た目はそれっぽくても、所詮は私の記憶の中の未練でしかないわけね……","ENG":"I suppose this was all just lingering regret in my memory...","TWN":"外表看似一樣，但最終不過是我記憶中的執念而已……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"고독한 존재라고요? 얼마든지요, 애버라인.","JPN":"孤独な存在ですか？　望むところです、アバーライン。","ENG":"A lonely existence? I welcome it, Abberline.","TWN":"孤獨的存在嗎？當然了，艾伯林。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"애초부터 당신을 떠나보낸 뒤로 저는 줄곧 외톨이였답니다.","JPN":"そもそもあなたに先立たれて以来、私はずっと一人ぼっちでした。","ENG":"Ever since I let you go, I've been alone anyway.","TWN":"自從你離開後，我一直都是孤身一人。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신과 이 세계를 되돌리기 위해서라면, 저는 얼마든지 외톨이로 남을 수 있어요.","JPN":"あなたとこの世界を取り戻すためなら、私はいくらでも一人になりましょう。","ENG":"If it means bringing you and this world back, I'll gladly stay that way.","TWN":"只要你和這個世界能後重回過去，我可以一直孤獨下去。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그게 무슨……?","JPN":"それはどういう……？","ENG":"What are you talking about...?","TWN":"那是什麼？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 이렇게 먼발치에서 당신을 지켜보는 것으로도 충분해요.","JPN":"私はこうして、ただ遠くからあなたを見守るだけで十分です。","ENG":"Just watching you from afar is enough for me.","TWN":"我能在遠處這樣看著你就足夠了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신만큼은 언제 어디서나 아름답고 우아한 백조로 남길 바라니까요.","JPN":"あなただけは、いつまでも美しく優雅な白鳥でいて欲しいから。","ENG":"I want you to always remain a beautiful, graceful swan, no matter where you are.","TWN":"我希望無論何時何地，你都能像優雅的天鵝一樣美麗。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어차피 이제 와서 당신의 손을 잡기에는, 제 손이 너무나 더러워져 버렸으니까요.","JPN":"どのみち、今更あなたの手を取るには、私の手は汚れきってしまった。","ENG":"Besides, my hands are far too tainted now to ever hold yours again.","TWN":"我的手已經太髒了，已經不配再與你攜手了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 늘 수수께끼 풀이가 업이라고 했죠?","JPN":"あなたはいつも謎解きが仕事だと言いましたよね？","ENG":"You always said solving riddles was your profession, didn't you?","TWN":"你總是說解謎是你的工作，對吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면 다시 만날 그 세계에서는 제가 당신의 수수께끼, 그 자체가 되어드리죠.","JPN":"でしたらまた会うその世界では、私があなたの謎そのものになってさしあげましょう。","ENG":"Then in the world we meet again, I'll be your greatest mystery.","TWN":"那麼在我們再次相遇的那個世界裡，我將成為你的謎題本身。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"언젠가 당신과 만났던 미지의 존재, 존 스미스처럼.","JPN":"かつてあなたと出会った未知なる存在、ジョン・スミスのように。","ENG":"Just like John Smith, the unknown figure you once met...","TWN":"就如同某天與你相遇的未知存在約翰·史密斯一樣。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"존 스미스라고……?","JPN":"ジョン・スミスだと……？","ENG":"John Smith...?","TWN":"約翰·史密斯？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아이린, 자네가 그걸 어떻게……?","JPN":"アイリーン、どうして君がその名を……？","ENG":"Irene, how do you know that name...?","TWN":"愛琳，你怎麼會知道？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"한심해요……!","JPN":"情けない……！","ENG":"You're pathetic...!","TWN":"真是無可救藥！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정말이지! 한심하다고요, 미래의 저……!","JPN":"本当に情けないです！　未来の私……！","ENG":"Seriously! You're pathetic, future me...!","TWN":"未來的我是真的讓人無語！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"And you are...?","TWN":"你是？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신에게 무슨 일이 있었는지는 모르겠지만, 저는 정말로 한심한 여자로 커버렸군요……!","JPN":"あなたに何があったのかは知りませんが、私はどうしようもなく情けない女になってしまったんですね……！","ENG":"I don't know what happened to you, but I turned out to be such a pitiful woman...!","TWN":"我不知道你經歷了什麼？但看來我真的變成了一個可悲的女人！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이래서야 스완이라는 이름이 아깝다고요!","JPN":"これではスワンの名が泣きます！","ENG":"The name Swan doesn't even suit you anymore!","TWN":"這樣的話，叫史旺這個名字就太可惜了！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"인정하기는 싫지만, 이미 당신도 알고 있잖아요?","JPN":"認めたくはありませんが、もうあなたもご存じでしょう？","ENG":"You don't want to admit it, but you know it's true, don't you?","TWN":"雖然不想承認，但你已經知道了吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저 남자, 애버라인은 누구보다도 공공의 이익을 우선시하는 사람이에요!","JPN":"あの男、アバーラインは誰よりも公共の利益を優先させる人です！","ENG":"That man, Abberline, is someone who always puts public interest above all else!","TWN":"那個男人，艾伯林是一個比任何人都優先考慮公共利益的人！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"상관도 없는 타인을 위해, 오지랖을 부리다가 침식병까지 걸려버린 멍청한 남자라고요……!","JPN":"関係のない他人のために、お節介を焼いて侵食病にまでなったバカみたいな男なんです……！","ENG":"He's a foolish man who got the Corruption Syndrome from trying to help people he didn't even know...!","TWN":"為了不相干的人多管閒事，結果還感染了侵蝕病的愚蠢男人！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그런 사람한테… 지금 대체 무슨 말을 하고 있는 건가요……!","JPN":"そんな彼に向って……いったい今、何を言っているのですか……！","ENG":"Just why... Why are you talking to him like that...?!","TWN":"對那種人……你現在到底在說什麼？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"자기를 살리기 위해, 다른 사람들을 희생시키겠다고요?","JPN":"自身を助けるために、他の人たちを犠牲にする？","ENG":"And yet, you're saying you'll sacrifice others to save him?","TWN":"為了拯救自己，就要犧牲其他人嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그런 말을 들으면, 저 남자가 정말로 기뻐할 것 같아요?","JPN":"そんなこと言われて、あの男が本心から喜ぶと思いますか？","ENG":"Do you think he'd be happy to hear that?","TWN":"聽到這樣的話，他會真的高興嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"알고 있을 텐데요? 그렇게 되돌려진 삶을 살아봤자, 저 남자에게는 저주나 다름없다는걸!","JPN":"知っているでしょう？　そうして戻した命を与えられたところで、あの男には呪い同然だということを！","ENG":"You know it, don't you? That kind of life would be a curse to him!","TWN":"你應該知道吧？即使過上那樣被逆轉的生活，對那個男人來說也無異於詛咒！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아니요. 이건 그 남자와 관계없어요.","JPN":"いいえ。これはあの男とは関係ありません。","ENG":"No. This has nothing to do with him.","TWN":"不，這和那個男人無關。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 원하는 거예요. 이게 제 바람이고, 제 선택이에요.","JPN":"私が欲しているのです。これが私の望みで、私の選択です。","ENG":"This is about what I want. My wish. My choice.","TWN":"這是我想要的。這是我的願望，也是我的選擇。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"오래전부터 이것을 이루기 위해서라면, 어떤 악역이든 받아들이겠다고 다짐했으니까.","JPN":"それを叶えるためなら、どんな悪役でも喜んで引き受けると決めたのですから。","ENG":"I swore long ago that I'd play the villain if that's what it took to make this happen.","TWN":"因為很久以前我就下定決心，為了實現這個目標，無論什麼？派角色我都願意接受。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그러니까 웃기지 말라고요! 당신……!","JPN":"もう、話にならないわ……！","ENG":"So don't make me laugh! You...!","TWN":"所以別說笑了！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아무리 그렇게 여린 마음을 속여가며 연기해 봤자, 제 눈은 못 속인다고요!","JPN":"そうやって脆い心を隠して演じきったつもりかは知りませんが、私の目は誤魔化せません！","ENG":"Even if you deceive your gentle heart and act, I can see right through you!","TWN":"無論你如何偽裝那顆柔軟的心，也騙不了我的眼睛！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"사실은 모두에게 사랑받고 싶은 주제에……! 사실은 악역 같은 건 맡고 싶지 않은 주제에……!","JPN":"本当はみんなに愛されたいくせに……！　本当は悪役なんかやりたくないくせに……！","ENG":"You just want to be loved...! You don't want to play the villain...!","TWN":"你其實是想被大家喜愛的……！其實是不想扮演反派角色的……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"사실은 외톨이 같은 건 되고 싶지 않은 주제에……!!","JPN":"本当は一人ぼっちになんて、なりたくないくせに……！！","ENG":"You don't want to be alone...!","TWN":"你其實並不想成為一個孤獨的人……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"사실은 저 남자를 동경하고… 한편으로는 따라잡고 싶다고 생각했던 주제에……!!","JPN":"本当はあの男に憧れて……一方では追いつきたいと思っていたくせに……！！","ENG":"You admire that man... And deep down, you wanted to stand beside him...!!","TWN":"你其實一直仰慕著那個男人……同時也想要追上他……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"자기 손이 더러워졌으니까, 먼발치에서 지켜보기만 하겠다고요?","JPN":"自分の手が汚れたから、遠くでただ見守るだけ？","ENG":"But you said your hands were too tainted, so you'd just watch from afar?","TWN":"因為自己的手髒了，就只想在遠處靜靜的看著嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"웃기지 마세요! 당신의 말은 하나부터 열까지 전부 거짓말뿐이잖아……!","JPN":"ふざけないで！　あなたの言ってることは、どれもこれも嘘ばっかり……！","ENG":"Give me a break! Every word out of your mouth is a lie...!","TWN":"別開玩笑了！你說的話從頭到尾全都是謊言……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……큿.","JPN":"……くっ。","ENG":"...Kgh.","TWN":"……哼。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무례하군요, 거기까지 하세요. 무명 시절의 저.","JPN":"無礼ですね。そこまでにしておきなさい、無名時代の私。","ENG":"How rude. That's enough out of you, me from the past.","TWN":"真是無禮，就到此為止吧。無名時期的我。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"시끄럽다고요! 미래의 저……!","JPN":"うるさいです！　未来の私……！","ENG":"Silence! Future me...!","TWN":"你吵死了！未來的我……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"세계를 되돌리겠다고요? 그렇게 과거에 집착한다고 해서 뭐가 달라지죠?","JPN":"世界を元に戻す？　そうやって過去に執着したところで何が変わるんですか？","ENG":"Rewind the world? What good is clinging to the past going to do?","TWN":"要把世界恢復原狀嗎？就算那麼執著於過去，又能改變什麼？？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이 진짜 저라면 기억하고 있겠죠? 스스로 이름 붙인 스완이라는 예명의 의미를……!","JPN":"あなたが本当に私なら、覚えているはずです。自分で付けたスワンという芸名の意味を……！","ENG":"If you're really me, then you should remember why I chose the name Swan...!","TWN":"如果你真的是我的話，就應該記得我自己取的藝名史旺的意義！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그건 각오였어요.","JPN":"それは覚悟でした。","ENG":"It was a vow.","TWN":"那是我的決心。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"밀라노 극장을 떠나며 과거를 잊고, 런던이라는 새로운 무대에 서기 위한 각오였다고요……!","JPN":"ミラノの劇場を後にして過去を忘れ、ロンドンという新しい舞台に立つための覚悟……！","ENG":"A vow to leave Milan Theater behind and step onto the new stage of London...!","TWN":"離開米蘭劇院，忘卻過去，決心在倫敦這個新舞台上展現自我！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그런데 참 이상하죠? 당신은 지금 또다시 과거로 도망치려 하고 있네요?","JPN":"なのにおかしいですね？　あなたは今、またしても過去に逃げようとしている。","ENG":"But it's strange, right? You're trying to run back to the past again.","TWN":"不過真奇怪啊？你現在又想逃回過去了嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"분명, 당신도 알고 있을 텐데요? 도망치는 것만으로는 아무것도 바꿀 수 없다는 것쯤은……!","JPN":"あなたもわかっているはずです。逃げるだけでは何も変えられないってことくらい……！","ENG":"You know as well as I do... that running away can't change anything...!","TWN":"你肯定也知道吧？光是逃避是無法改變任何事情的！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그게 아니라면, 설마 지난 날의 과오를 잊으셨다고 할 셈인가요?","JPN":"まさか過去の過ちを忘れたとでも言うのですか？","ENG":"Or are you planning to say you've forgotten your past mistakes?","TWN":"不然的話，難道你是想說你已經忘記了過去的過錯嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럴 리 없겠죠! 어차피 당신은 그 어떤 것도 망각할 수 없는 여자니까요……!","JPN":"そんなはずありませんよね！　所詮あなたは、何一つ忘れることのできない女ですから……！","ENG":"There's no way. You're not the kind of woman who can forget anything...!","TWN":"那是不可能的！因為你是個無法忘記任何事情的女人……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 나중에 후회하지 말고, 적어도 마지막에는 솔직하게 본심을 전하라고요……!","JPN":"ならば後になって後悔などせず、せめて最後くらい素直な気持ちを伝えてみなさいよ……！","ENG":"Then don't regret it later. At the very least, be honest with yourself at the end...!","TWN":"那你至少在最後坦誠地表達自己的真心，別再做後悔的事了！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제가 당신이라면……!","JPN":"私があなただったら……！","ENG":"If I were you...!","TWN":"如果我是你的話！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"꺄아악……!!","JPN":"きゃああっ……！！","ENG":"Kyaaaah...!!","TWN":"呃啊啊！？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 닥치라고 했을 텐데요? 무명 시절의 저……!","JPN":"黙れと言ったのが聞こえませんでしたか？　無名時代の私……！","ENG":"I said shut up, didn't I? You pathetic, nameless version of me...!","TWN":"我應該讓你閉嘴了吧？無名時期的我！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아무리 허상이라고 해도, 감히 제 주제도 모르고 지껄여 대는군요……!","JPN":"いくら虚像とはいえ、身の程も知らないでよく喋りますね……！","ENG":"Even if you're just a shadow, how dare you run your mouth like that...!","TWN":"區區幻影，也敢不自量力地胡言亂語！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이봐, 괜찮아!? 꼬마 스완!?","JPN":"ちょっと、大丈夫！？　チビスワン！！","ENG":"Hey, are you okay?! Kid Swan?!","TWN":"喂，你沒事吧！？小史旺！？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"크윽, 누가 꼬마라는 거예요……!","JPN":"くっ、誰がチビですか……！","ENG":"Grrk...! Who are you calling a kid...?!","TWN":"呃，誰說我小的！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후회하지 말라고요……?","JPN":"後悔せずに、と言いましたか……？","ENG":"Don't regret it...?","TWN":"……不要後悔嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"애초에 제가 유일하게 후회하는 건... 무력했던 무명 시절의 저, 바로 당신이에요……!","JPN":"そもそも私が唯一後悔しているのは……無力だった無名時代の私、そう、あなたです……！","ENG":"The only thing I regret... is the helpless and unknown me. You...!","TWN":"最初我唯一後悔的就是……無能的無名時期的我，也就是你！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어울리지도 않는 거창한 배역을 맡은 주제에, 아무것도 모르고 또 알려고 노력하지도 않죠.","JPN":"身に余る大役を任されておいて、何も知らず、また知ろうともしない。","ENG":"You took on a grand role that didn't suit you, and yet you knew nothing. Didn't even try to understand.","TWN":"明明擔任了不合適的大角色，卻什麼也不知道，也不努力去瞭解。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 알고 있을 텐데요, 무지는 죄랍니다.","JPN":"あなたもわかっているはずです、無知は罪だと。","ENG":"You know, don't you? Ignorance is a sin.","TWN":"你應該也知道，無知也是一種罪過。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 더 빨리 모든 걸 눈치채고, 더 빨리 모두와 만났다면, 더 많은 걸 바꿀 수 있었겠죠.","JPN":"あなたがもっと早く全てに気づき、もっと早くみんなと出会えていれば、もっとたくさんのことを変えられた。","ENG":"If you'd realized everything sooner, if you'd met everyone earlier, so much could've changed.","TWN":"如果你能更早察覺到一切，並更早與大家見面，或許能改變更多事情。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"만약, 그렇다면 우리 세계는 다른 결말을 맞이할 수도 있었어요……!","JPN":"もしそうだったら、私たちの世界は違う結末を向かえたかもしれない……！","ENG":"Had that been the case, our world might have seen a different conclusion...!","TWN":"如果是那樣的話，我們的世界可能會迎來不同的結局！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아이린……?","JPN":"アイリーン……？","ENG":"Irene...?","TWN":"愛琳？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어쩌면, 자네 설마……?","JPN":"もしかして、君は……？","ENG":"Wait, you're not...","TWN":"也許，你難道……？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"좋아요, 때 마침 시작되었군요.","JPN":"いいでしょう、ちょうど始まりました。","ENG":"Perfect timing. It's beginning.","TWN":"好吧，正好開始了。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결국, 모든 것은 각본대로…….","JPN":"結局、すべては脚本どおりに……","ENG":"In the end, everything according to the script...","TWN":"最終，一切都將按照劇本進行……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금 이 순간이 지금까지 준비해 온 각본의 마지막 엔딩이랍니다.","JPN":"今この瞬間が、今まで準備してきた脚本の最後のエンディングです。","ENG":"This moment marks the final ending of the story I've prepared.","TWN":"此刻就是我一直以來準備的劇本的最終結局。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"동시에 세계의 끝을 너머, 모든 이야기를 처음으로 되돌리는 시작점이라고도 할 수 있겠죠.","JPN":"そして同時に世界の終わりを超えて、全ての物語を振り出しに戻すスタート地点とも言えるでしょう。","ENG":"And at the same time, the start of something new. The beginning of reverting all the stories to the start.","TWN":"同時也可以說是超越世界盡頭，將所有故事回到起點的開始。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"자, 잠깐! 저 괴물은 대체……?","JPN":"ま、待って！　あの化け物はいったい……？","ENG":"W-wait! What is that monster...?!","TWN":"等一下！怪物到底是……？"},"stage":{"bg":"SWANSONG_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인! 무언가가 밤 하늘을 찢고 나타나고 있어요……!","JPN":"アバーライン！　夜空を引き裂くように、何かが現れています……！","ENG":"Abberline! Something's tearing through the night sky!","TWN":"艾伯林！有東西正在撕裂夜空！"},"stage":{"bg":"SWANSONG_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모두들 듣게! 지금 즉시 이 자리에서 전원 이탈하도록……!","JPN":"全員聞きたまえ！　ただちにこの場から離れろ……！","ENG":"Everyone, listen! Leave this place immediately...!","TWN":"大家聽著！立刻從這裡撤離！"},"stage":{"bg":"SWANSONG_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"저건 인간이 어쩔 수 있는 상대가 아니야……!","JPN":"あれは人間がどうこうできる相手ではない……！","ENG":"That thing isn't something humans can fight...!","TWN":"那不是人類能夠對付的對手！"},"stage":{"bg":"SWANSONG_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"……이거 믿을 수 없군.","JPN":"……信じられない。","ENG":"...Unbelievable.","TWN":"……這真是難以置信。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"설마, 인간이 데우스 엑스 마키나를 쓰러트릴 줄이야…….","JPN":"まさか、人間の身でデウス・エクス・マキナを倒してしまうとは……","ENG":"I can't believe humans actually brought down a Deus Ex Machina...","TWN":"沒想到，人類竟然能打倒機械神……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"데우스 엑스 마키나라고요……?","JPN":"デウス・エクス・マキナ……？","ENG":"Deus Ex Machina...?","TWN":"機械神？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네, 이 세계를 끝내기 위해 나타난 거짓된 신이라고 할 수 있지.","JPN":"ああ、この世界に終焉をもたらすために現れた、偽りの神さ。","ENG":"Yes. A Hollow God that meant to bring about the end of this world.","TWN":"是的，可以說是為了終結這個世界而出現的虛神。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어쩌면 저 이방인들은 내가 예상했던 것보다 훨씬 더 강할지도 모르겠군.","JPN":"もしかすると、あの異邦人たちは私の予想よりも遥かに強いのかもしれんな。","ENG":"Those outsiders may be far stronger than I expected.","TWN":"也許那些外邦人比我預想的要強得多。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"세계를 끝내기 위해 나타난 신…….","JPN":"世界に終焉をもたらすために現れた神……","ENG":"A god meant to end the world...","TWN":"為了終結世界而出現的神……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면… 그 거짓된 신을 쓰러트렸으니까 이제 모두 끝난 건가요……?","JPN":"でしたら……その偽りの神を倒したから、これで全部終わったのですか……？","ENG":"Then... now that the false god is defeated, is everything over...?","TWN":"那麼……既然那個虛神已經被打倒了，現在一切都結束了嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 그렇지는 않아.","JPN":"いや、そうではない。","ENG":"No. I'm afraid it's not.","TWN":"不，不是這樣的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"한번 깨져버린 컵은 결코 원래대로 돌아오지 않으니까.","JPN":"一度割れてしまったコップは、決して元の形には戻らないのと同じように。","ENG":"Once a cup is broken, it can never be made whole again.","TWN":"破鏡重圓終有隙。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마찬가지로 한 번 임계치에 다다른 세계가 되돌아올 일은 없겠지.","JPN":"一度臨界値に到達した世界が元に戻ることはない。","ENG":"Likewise, a world that has reached its breaking point won't just recover.","TWN":"同樣，一旦達到臨界點的世界就不會再回來了吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇지만…….","JPN":"でも……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 여자, 미래의 저는 세계를 되돌릴 수 있다고 했잖아요.","JPN":"彼女は、未来の私は世界を元に戻せると言いました。","ENG":"That woman, my future self, said we could turn the world back.","TWN":"那個女人，未來的我不是說可以讓世界恢復原樣嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그게 정말로 가능할까요?","JPN":"それは本当に可能なのでしょうか？","ENG":"Is that really possible?","TWN":"那真的可能嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"글쎄, 그건 나 역시도 잘 모르겠군.","JPN":"さあ、それは私にもわからないね。","ENG":"Honestly, I don't know either.","TWN":"這個嘛，我也不太清楚。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 뭐든지 다 아는 줄 알았는데, 당신도 모르는 게 있네요.","JPN":"ふふ、何でも知っていると思っていましたが、あなたにもわからないものはあるんですね。","ENG":"Haha. I thought you knew everything, but even you have something you don't know.","TWN":"呵呵，我以為你什麼都知道，原來你也有不知道的事情啊。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그야 물론이지 않나?","JPN":"当然のことじゃないか。","ENG":"Haha, of course I do.","TWN":"呵呵，那當然不是嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나라고 어떻게 이 세계의 모든 진실을 알고 있겠어?","JPN":"私とて、この世界の全ての真実を知ることは叶わないよ。","ENG":"There's no way I could know every truth about this world.","TWN":"我怎麼可能知道這個世界的所有真相呢？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"But still...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인……?","JPN":"アバーライン……？","ENG":"Abberline...?","TWN":"艾伯林？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"지금 어디 가는 거예요? 설마, 그쪽은……?","JPN":"どこに行くのですか？　そっちはまさか……？","ENG":"Where are you going? That direction is...?","TWN":"現在要去哪裡？難道，是那邊……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 적어도 마지막에는 나에게 주어진 역할을 다해야겠지.","JPN":"せめて、最後は自分に課せられた役割を果たすべきだろう。","ENG":"At the very least, I need to fulfill the role given to me in the end.","TWN":"但至少在最後，我必須完成賦予我的使命。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"수수께끼 풀이가 내 업일 테니까.","JPN":"謎解きが、私の仕事のはずだから。","ENG":"Solving mysteries is my job, after all.","TWN":"解謎是我的工作。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 이제 이 사진은 돌려주도록 하지.","JPN":"だから、もうこの写真は返そう。","ENG":"So, I think it's time that I returned this photo to its owner.","TWN":"所以現在該把這張照片還給你了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이건…? 이걸 왜 지금……?","JPN":"これは……？　どうして今これを……？","ENG":"What is this...? Why now...?","TWN":"這是……？為什麼現在把這個……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"잘 듣게, 스완.","JPN":"よく聞きたまえ、スワン。","ENG":"Listen carefully, Swan.","TWN":"史旺，你聽好了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이곳으로부터 북쪽 숲을 넘어, 조금만 더 가면…….","JPN":"ここから北の森を越えてもう少し進んだ先に……","ENG":"If you head north from here, past the forest, and go just a little farther...","TWN":"從這裡穿過北邊森林，再往前走一點……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계의 것이 아닌 유적이 있다네. 어느 사건을 통해 알게 된 곳이지.","JPN":"この世界のものではない遺跡がある。とある事件で知った場所だ。","ENG":"There will be ruins that are not of this world. I learned about that place through another case.","TWN":"有一個不屬於這個世界的遺跡。我通過某個案件得知了那裡。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"언제부터 거기 있었고, 어떤 문명의 유적인지는 아무도 모르지만…….","JPN":"いつからそこにあって、どんな文明の遺跡なのか知る者は誰もいないが……","ENG":"I don't know how long it has been there, or from which civilization...","TWN":"沒人知道它從什麼時候開始存在，也不知道它屬於哪個文明的遺跡……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그건 틀림없이 다른 세계로 통하는 <color=#ffd34c>문</color>…….","JPN":"それは間違いなく別の世界に通じる<color=#ffd34c>扉</color>……","ENG":"But I do know that it is a <color=#ffd34c>door</color> to another world...","TWN":"但我知道那肯定是通往<color=#ffd34c>另一個世界</color>的門……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"다른 세계로 통하는 문……?","JPN":"別の世界に通じる扉……？","ENG":"A door to another world...?","TWN":"通往其他世界的門……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 지금 저 보고 혼자 도망치라는 건가요?","JPN":"では、私に一人で逃げろというのですか？","ENG":"Then are you telling me to run away on my own right now?","TWN":"那你是要我自己逃跑嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정말이지. 저를 너무 얕보고 있어요, 애버라인.","JPN":"まったく。私を甘く見すぎですよ、アバーライン。","ENG":"You have really underestimated me, Abberline.","TWN":"你太小看我了，艾伯林。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"도망치는 것만으로는 아무것도 바꿀 수 없어요.","JPN":"逃げるだけでは何も変えられません。","ENG":"Running away can't change anything.","TWN":"只是一味地逃避，最終不會改變任何事情。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그건 지금껏 도망쳐왔던 제가 가장 잘 알고 있다고요!","JPN":"それは今まで逃げてきた私が一番よくわかっているんです！","ENG":"I know that better than anyone, after running away all this time!","TWN":"那一點，我這個一直逃避至今的人最清楚不過了！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 틀렸어. 이건 도망치는 게 아니야.","JPN":"いや、違う。これは逃げるのではない。","ENG":"No, you're wrong. This isn't running away.","TWN":"不，你錯了。這不是逃避。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"더는 과거에 얽매여 있는 것이 아니라, <color=#ffd34c>미래</color>로 나아가는 걸세.","JPN":"過去に囚われず、<color=#ffd34c>未来</color>へ進むことさ。","ENG":"It's not clinging to the past anymore. It's moving toward the <color=#ffd34c>future</color>.","TWN":"我已經不再拘泥過去，邁向<color=#ffd34c>未來</color>了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"미래라고요……?","JPN":"未来へ……？","ENG":"The future...?","TWN":"未來……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어떤 수수께끼라도 답이 있기 마련이지.","JPN":"どんな謎にも答えはある。","ENG":"Every riddle has an answer.","TWN":"任何謎題，終究都會有答案。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이게 내가 내린 답이야. 그러니까 추하더라도, 힘겹더라도 끝까지 포기하지 말게.","JPN":"これが私の見出した答えだ。だから惨めでも、辛くても、最後まで諦めないでくれ。","ENG":"This is the answer I've reached. So even if it's ugly, even if it's painful, don't give up until the very end.","TWN":"這就是我得到的結論。所以就算醜陋、艱辛，到最後也不要放棄。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"모르겠어요…! 당신 말은 무슨 뜻인지 하나도 모르겠다고요……!","JPN":"わからない……！　あなたが何を言ってるのか、全然意味がわかりません……！","ENG":"I don't understand...! I don't understand what you're saying at all...!","TWN":"我不懂……！你說的話我一點都聽不懂……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"미래로 나아간다고요? 그렇다면, 같이 가면 되잖아요……!","JPN":"未来へ進む？　なら、一緒に行けばいいじゃないですか……！","ENG":"Moving toward the future? Then we can go together...!","TWN":"邁向未來？既然如此，那一起走不就好了……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 자네가 나아가야 할 미래에 나는 없어.","JPN":"いや、君が進むべき未来に私はいない。","ENG":"No. The future you must walk toward doesn't include me.","TWN":"不，你要邁向的未來裡沒有我。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나에겐 아직 이곳에서 해결해야 할 수수께끼가 남은 모양이니까.","JPN":"私にはまだ、ここで解くべき謎が残っているようだからね。","ENG":"It seems I still have a riddle to solve here.","TWN":"這裡對我來說，似乎還有需要解開的謎題。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그게 무슨…….","JPN":"どういう……","ENG":"What do you mean by that...?","TWN":"那是什麼意思……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"무엇보다도 말이지…….","JPN":"何より……","ENG":"More than anything...","TWN":"最重要的是……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나는 자네를 무척이나 신뢰하고 있다네.","JPN":"私は君をとても信頼している。","ENG":"I trust you deeply.","TWN":"我非常信任你。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"언제 어디서나 자네가 잘 해줄 거라고 믿고 있어.","JPN":"いつどこでも、君は上手くやってくれると信じている。","ENG":"No matter when or where, I believe you'll do well.","TWN":"無論何時何地，我都相信你一定能辦到。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"왜냐하면 자네는 나의 진정한 파트너니까.","JPN":"なぜなら君は私の、真のパートナーだからだ。","ENG":"Because you are my true partner.","TWN":"因為你是我真正的夥伴。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"알겠어요, 애버라인.","JPN":"わかりました、アバーライン。","ENG":"All right, Abberline.","TWN":"我明白了，艾伯林。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 여기서 작별이에요.","JPN":"では、ここでお別れですね。","ENG":"Then this is goodbye.","TWN":"那麼，就在這裡道別吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지금 돌이켜보면 어리석은 판단이었어.","JPN":"今思い返せば、愚かな判断だった。","ENG":"It was a foolish decision looking back at it now.","TWN":"現在回想起來，那是個愚蠢的決定。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네에게 더 많은 걸 알려주고, 더 많은 인연을 쌓게 해야 했어…….","JPN":"君にもっとたくさんのことを教えて、より多くの絆を築かせてあげるべきだったんだ……","ENG":"I should've told you more and built a relationship with you...","TWN":"應該告訴你更多，建立更多的聯繫……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"망각의 여신에게 미움받는 자네인 만큼, 자네에게 소중한 기억을 남겨줬어야 했어.","JPN":"君は忘却の女神に嫌われているから、君に大切な思い出を残してあげるべきだった。","ENG":"For you are shunned by the goddess of oblivion, I should've left you with precious memories.","TWN":"既然你被遺忘女神所厭惡，我本該為你留下珍貴的記憶。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 구태여 <color=#ffd34c>내</color>가 아니더라도…….","JPN":"だが必ずしも<color=#ffd34c>私</color>でなくても……","ENG":"But even if it isn't <color=#ffd34c>me</color>...","TWN":"但是，就算不是由<color=#ffd34c>我</color>動手……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 나아갈 미래에는, 틀림없이 그 역할을 해줄 <color=#ffd34c>누군가</color>가 있겠지.","JPN":"君が進む未来には、きっとその役割を果たしてくれる<color=#ffd34c>誰か</color>がいるだろう。","ENG":"In the future you walk toward, there will surely be <color=#ffd34c>someone</color> who can fulfill that role.","TWN":"在你即將邁向的未來裡，一定有<color=#ffd34c>某個人</color>會擔任那個角色吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리 세계는 여기서 끝나더라도, 최후의 걸작인 자네가 살아남는다면 우리의 승리라네.","JPN":"私たちの世界はここで終わっても、最後の傑作である君が生き残ったなら私たちの勝利だ。","ENG":"Our world might end here, but it will be our victory if you, the final masterpiece, survive.","TWN":"即使我們的世界在此終結，只要你這幅最後的傑作能活下來，那就是我們的勝利。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나의 사랑스러운 파트너라면…….","JPN":"私の愛しいパートナーなら……","ENG":"My beloved partner...","TWN":"如果是我親愛的夥伴啊……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"보이지 않는 실타래처럼 얽힌 세계의 법칙을 언젠가 간파해 낼 수 있을 테니까.","JPN":"目に見えない糸のように絡まっている世界の法則を、いつか見抜けるはずだからね。","ENG":"Someday, you'll be able to unravel the laws of this world that are intertwined by invisible threads.","TWN":"你終有一天能夠洞悉，有如看不見的絲線般交織的世界法則。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래…….","JPN":"そう……","ENG":"Yes...","TWN":"是啊……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>그녀</color>가 그랬던 것처럼…….","JPN":"<color=#ffd34c>彼女</color>がそうだったように……","ENG":"Just as <color=#ffd34c>she</color> once did...","TWN":"就像<color=#ffd34c>她</color>曾經做到的那樣……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};